import Complex from "../../../../../../../../../../../subject_repositories/Complex.js/complex.js";

describe('Complex div', () => {
  it('correctly divides complex numbers when divisor has equal magnitude real and imaginary parts', () => {
    // (3 + 4i) / (1 - 1i) where |c|=|d|=1
    // = (3+4i)(1+1i)/2 = (3+3i+4i-4)/2 = (-1+7i)/2 = -0.5 + 3.5i
    const result = new Complex(3, 4).div(new Complex(1, -1));
    expect(result.re).toBeCloseTo(-0.5, 14);
    expect(result.im).toBeCloseTo(3.5, 14);
  });
});
```

